// 难度级别 - 移除的数字数量
export const DIFFICULTY = {
  EASY: 30,
  MEDIUM: 40,
  HARD: 50,
} as const;

export const COLORS = {
  BACKGROUND: '#f0f0f0',
  GRID_LINE: '#333333',
  BOX_LINE: '#000000',
  CELL_BG: '#ffffff',
  CELL_SELECTED: '#bbdefb',
