  Z: { shape: [[1,1,0],[0,1,1]], color: '#f00000' },
  J: { shape: [[1,0,0],[1,1,1]], color: '#0000f0' },
  L: { shape: [[0,0,1],[1,1,1]], color: '#f0a000' },
};

export const TETROMINO_TYPES = Object.keys(TETROMINOS);

// 消行攻击规则
export const ATTACK_LINES: Record<number, number> = {
  1: 0,
  2: 1,
  3: 2,
  4: 4,
};

export const GARBAGE_COLOR = '#888888';

// 速度
export const BASE_SPEED = 800;
export const SPEED_DECREASE = 50;
export const MIN_SPEED = 100;

// AI
export const AI_THINK_TIME = 500;

export const COLORS = {
  BACKGROUND: '#0a0a1a',
  BOARD_BG: '#1a1a2e',
  GRID_LINE: '#2a2a4e',
  GHOST: 'rgba(255,255,255,0.15)',
  BORDER: '#4a4a6a',
  SCORE_TEXT: '#ffffff',
  LABEL_TEXT: '#888888',
} as const;

import { GameEngine } from '@/core/GameEngine';
import {
  CANVAS_WIDTH, CANVAS_HEIGHT, BALL_RADIUS, GRAVITY, FRICTION,
  BOUNCE_DAMPING, FLIPPER_LENGTH, FLIPPER_REST_ANGLE, FLIPPER_ACTIVE_ANGLE,
  FLIPPER_SPEED, LEFT_FLIPPER_X, LEFT_FLIPPER_Y, RIGHT_FLIPPER_X, RIGHT_FLIPPER_Y,
  LAUNCHER_X, LAUNCHER_Y, LAUNCHER_WIDTH, LAUNCHER_HEIGHT, LAUNCHER_POWER,
  BUMPER_RADIUS, BUMPER_SCORE, TARGET_WIDTH, TARGET_HEIGHT, TARGET_SCORE,
  WALL_THICKNESS, DRAIN_Y, MAX_LIVES, COLORS,
  Bumper, Target, FlipperState,
} from './constants';

export class PinballEngine extends GameEngine {
  private _ball = { x: LAUNCHER_X, y: LAUNCHER_Y, vx: 0, vy: 0, active: false };
  private _leftFlipper: FlipperState = {
    x: LEFT_FLIPPER_X, y: LEFT_FLIPPER_Y,
    angle: FLIPPER_REST_ANGLE, active: false, side: 'left',
  };
  private _rightFlipper: FlipperState = {
    x: RIGHT_FLIPPER_X, y: RIGHT_FLIPPER_Y,
    angle: -FLIPPER_REST_ANGLE, active: false, side: 'right',
  };
  private _bumpers: Bumper[] = [];
  private _targets: Target[] = [];
  private _lives = MAX_LIVES;
  private _launcherCompressed = 0;
  private _leftKey = false;
  private _rightKey = false;
  private _launchKey = false;

  protected onInit(): void {
    this.setupBumpers();
    this.setupTargets();
    this.resetBall();
  }

  protected onStart(): void {
    this._lives = MAX_LIVES;
    this._score = 0;
    this.resetBall();
    this.setupBumpers();
    this.setupTargets();
  }

  protected update(deltaTime: number): void {
    if (this._status !== 'playing') return;

    const dt = Math.min(deltaTime, 32) / 16; // 归一化到 ~60fps

    // 更新挡板角度
    this.updateFlippers(dt);

    // 弹射器蓄力
    if (this._launchKey && !this._ball.active) {
      this._launcherCompressed = Math.min(1, this._launcherCompressed + 0.03 * dt);
    }

    if (!this._ball.active) return;

    // 重力
    this._ball.vy += GRAVITY * dt;

    // 摩擦
    this._ball.vx *= Math.pow(FRICTION, dt);
    this._ball.vy *= Math.pow(FRICTION, dt);

    // 移动
    this._ball.x += this._ball.vx * dt;
    this._ball.y += this._ball.vy * dt;

    // 墙壁碰撞
    this.checkWallCollisions();

    // Bumper 碰撞
    this.checkBumperCollisions();

    // Target 碰撞
    this.checkTargetCollisions();

    // 挡板碰撞
    this.checkFlipperCollision(this._leftFlipper, dt);
    this.checkFlipperCollision(this._rightFlipper, dt);

    // 更新 bumper 动画
    for (const b of this._bumpers) {
      if (b.hit) {
        b.hitTimer -= deltaTime;
        if (b.hitTimer <= 0) b.hit = false;
      }
    }

    // 球掉出底部
    if (this._ball.y > DRAIN_Y) {
      this._lives--;
      this.emit('statusChange', this._status);
      if (this._lives <= 0) {
        this.gameOver();
      } else {
        this.resetBall();
      }
    }
  }

  protected onRender(ctx: CanvasRenderingContext2D, w: number, h: number): void {
    ctx.fillStyle = COLORS.BACKGROUND;
    ctx.fillRect(0, 0, w, h);

    // 墙壁
    ctx.fillStyle = COLORS.WALL;
    ctx.fillRect(0, 0, WALL_THICKNESS, h);
    ctx.fillRect(w - WALL_THICKNESS, 0, WALL_THICKNESS, h);
    ctx.fillRect(0, 0, w, WALL_THICKNESS);

    // 弹射通道右墙
    ctx.fillRect(LAUNCHER_X - LAUNCHER_WIDTH / 2 - WALL_THICKNESS, 0, WALL_THICKNESS, DRAIN_Y);

    // Bumpers
    for (const b of this._bumpers) {
      ctx.fillStyle = b.hit ? COLORS.BUMPER_HIT : COLORS.BUMPER;
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.radius, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = '#fff';
      ctx.lineWidth = 2;
      ctx.stroke();
    }

    // Targets
    for (const t of this._targets) {
      ctx.fillStyle = t.hit ? COLORS.TARGET_HIT : COLORS.TARGET;
      ctx.fillRect(t.x - t.width / 2, t.y - t.height / 2, t.width, t.height);
    }

    // 挡板
    this.renderFlipper(ctx, this._leftFlipper);
    this.renderFlipper(ctx, this._rightFlipper);

    // 弹射器
    const lx = LAUNCHER_X - LAUNCHER_WIDTH / 2;
    const ly = LAUNCHER_Y - LAUNCHER_HEIGHT;
    const compressedH = LAUNCHER_HEIGHT * (1 - this._launcherCompressed * 0.5);
    ctx.fillStyle = this._launcherCompressed > 0 ? COLORS.LAUNCHER_COMPRESSED : COLORS.LAUNCHER;
    ctx.fillRect(lx, LAUNCHER_Y - compressedH, LAUNCHER_WIDTH, compressedH);

    // 球
    if (this._ball.active || !this._ball.active) {
      ctx.fillStyle = COLORS.BALL;
      ctx.beginPath();
      ctx.arc(this._ball.x, this._ball.y, BALL_RADIUS, 0, Math.PI * 2);
      ctx.fill();
    }

    // 生命
    ctx.fillStyle = COLORS.SCORE;
    ctx.font = '16px sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText(`Lives: ${this._lives}`, 20, h - 15);
    ctx.textAlign = 'right';
    ctx.fillText(`Score: ${this._score}`, w - 20, h - 15);
  }

  handleKeyDown(key: string): void {
    if (this._status !== 'playing') return;
    if (key === 'z' || key === 'Z' || key === 'ArrowLeft') this._leftKey = true;
    if (key === 'm' || key === 'M' || key === 'ArrowRight') this._rightKey = true;
    if (key === ' ') {
      this._launchKey = true;
      if (!this._ball.active) {
        this._ball.active = true;
        this._ball.vy = -LAUNCHER_POWER * this._launcherCompressed;
        this._ball.vx = -1;
        this._launcherCompressed = 0;
      }
    }
  }

  handleKeyUp(key: string): void {
    if (key === 'z' || key === 'Z' || key === 'ArrowLeft') this._leftKey = false;
    if (key === 'm' || key === 'M' || key === 'ArrowRight') this._rightKey = false;
    if (key === ' ') this._launchKey = false;
  }

  getState(): Record<string, unknown> {
    return {
      ball: this._ball,
      leftFlipper: this._leftFlipper,
      rightFlipper: this._rightFlipper,
      bumpers: this._bumpers,
      targets: this._targets,
      lives: this._lives,
      launcherCompressed: this._launcherCompressed,
    };
  }

  // ========== 内部方法 ==========

  private setupBumpers(): void {
    this._bumpers = [
      { x: 160, y: 200, radius: BUMPER_RADIUS, score: 100, hit: false, hitTimer: 0 },
      { x: 320, y: 200, radius: BUMPER_RADIUS, score: 100, hit: false, hitTimer: 0 },
      { x: 240, y: 320, radius: BUMPER_RADIUS, score: 150, hit: false, hitTimer: 0 },
      { x: 140, y: 420, radius: BUMPER_RADIUS * 0.8, score: 200, hit: false, hitTimer: 0 },
      { x: 340, y: 420, radius: BUMPER_RADIUS * 0.8, score: 200, hit: false, hitTimer: 0 },
    ];
  }

  private setupTargets(): void {
    this._targets = [
      { x: 120, y: 120, width: TARGET_WIDTH, height: TARGET_HEIGHT, score: TARGET_SCORE, hit: false },
      { x: 200, y: 100, width: TARGET_WIDTH, height: TARGET_HEIGHT, score: TARGET_SCORE, hit: false },
      { x: 280, y: 100, width: TARGET_WIDTH, height: TARGET_HEIGHT, score: TARGET_SCORE, hit: false },
      { x: 360, y: 120, width: TARGET_WIDTH, height: TARGET_HEIGHT, score: TARGET_SCORE, hit: false },
    ];
  }

  private resetBall(): void {
    this._ball = {
      x: LAUNCHER_X,
      y: LAUNCHER_Y - 20,
      vx: 0,
      vy: 0,
      active: false,
    };
    this._launcherCompressed = 0;
  }

  private updateFlippers(dt: number): void {
    this._leftFlipper.active = this._leftKey;
    this._rightFlipper.active = this._rightKey;

    const targetLeft = this._leftFlipper.active ? FLIPPER_ACTIVE_ANGLE : FLIPPER_REST_ANGLE;
    const targetRight = this._rightFlipper.active ? -FLIPPER_ACTIVE_ANGLE : -FLIPPER_REST_ANGLE;

    if (this._leftFlipper.angle < targetLeft) {
      this._leftFlipper.angle = Math.min(targetLeft, this._leftFlipper.angle + FLIPPER_SPEED * dt);
    } else if (this._leftFlipper.angle > targetLeft) {
      this._leftFlipper.angle = Math.max(targetLeft, this._leftFlipper.angle - FLIPPER_SPEED * dt);
    }

    if (this._rightFlipper.angle > targetRight) {
      this._rightFlipper.angle = Math.max(targetRight, this._rightFlipper.angle - FLIPPER_SPEED * dt);
    } else if (this._rightFlipper.angle < targetRight) {
      this._rightFlipper.angle = Math.min(targetRight, this._rightFlipper.angle + FLIPPER_SPEED * dt);
    }
  }

  private checkWallCollisions(): void {
    const b = this._ball;
    // 左墙
    if (b.x - BALL_RADIUS < WALL_THICKNESS) {
      b.x = WALL_THICKNESS + BALL_RADIUS;
      b.vx = Math.abs(b.vx) * BOUNCE_DAMPING;
    }
    // 右墙
    if (b.x + BALL_RADIUS > CANVAS_WIDTH - WALL_THICKNESS) {
      b.x = CANVAS_WIDTH - WALL_THICKNESS - BALL_RADIUS;
      b.vx = -Math.abs(b.vx) * BOUNCE_DAMPING;
    }
    // 顶墙
    if (b.y - BALL_RADIUS < WALL_THICKNESS) {
      b.y = WALL_THICKNESS + BALL_RADIUS;
      b.vy = Math.abs(b.vy) * BOUNCE_DAMPING;
    }
    // 弹射通道左墙
    const channelLeft = LAUNCHER_X - LAUNCHER_WIDTH / 2 - WALL_THICKNESS;
    if (b.x < LAUNCHER_X && b.x + BALL_RADIUS > channelLeft && b.y < DRAIN_Y) {
      b.x = channelLeft - BALL_RADIUS;
      b.vx = -Math.abs(b.vx) * BOUNCE_DAMPING;
    }
  }

  private checkBumperCollisions(): void {
    for (const bumper of this._bumpers) {
      const dx = this._ball.x - bumper.x;
      const dy = this._ball.y - bumper.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const minDist = BALL_RADIUS + bumper.radius;

      if (dist < minDist) {
        // 弹开
        const nx = dx / dist;
        const ny = dy / dist;
        this._ball.x = bumper.x + nx * minDist;
        this._ball.y = bumper.y + ny * minDist;

        const dot = this._ball.vx * nx + this._ball.vy * ny;
        this._ball.vx -= 2 * dot * nx;
        this._ball.vy -= 2 * dot * ny;
        this._ball.vx *= 1.1;
        this._ball.vy *= 1.1;

        bumper.hit = true;
        bumper.hitTimer = 200;
        this.addScore(bumper.score);
      }
    }
  }

  private checkTargetCollisions(): void {
    for (const target of this._targets) {
      if (target.hit) continue;
      const dx = Math.abs(this._ball.x - target.x);
      const dy = Math.abs(this._ball.y - target.y);
      if (dx < target.width / 2 + BALL_RADIUS && dy < target.height / 2 + BALL_RADIUS) {
        target.hit = true;
        this.addScore(target.score);
        // 反弹
        if (dx > dy) {
          this._ball.vx = -this._ball.vx * BOUNCE_DAMPING;
        } else {
          this._ball.vy = -this._ball.vy * BOUNCE_DAMPING;
        }
      }
    }
  }

  private checkFlipperCollision(flipper: FlipperState, dt: number): void {
    const endX = flipper.x + Math.cos(flipper.angle) * FLIPPER_LENGTH;
    const endY = flipper.y + Math.sin(flipper.angle) * FLIPPER_LENGTH;

    // 简化的线段碰撞检测
    const dx = endX - flipper.x;
    const dy = endY - flipper.y;
    const len = Math.sqrt(dx * dx + dy * dy);
    const nx = -dy / len;
    const ny = dx / len;

    const toBallX = this._ball.x - flipper.x;
    const toBallY = this._ball.y - flipper.y;
    const proj = (toBallX * dx + toBallY * dy) / (len * len);
    const clampedProj = Math.max(0, Math.min(1, proj));
    const closestX = flipper.x + clampedProj * dx;
    const closestY = flipper.y + clampedProj * dy;

    const distX = this._ball.x - closestX;
    const distY = this._ball.y - closestY;
    const dist = Math.sqrt(distX * distX + distY * distY);

    if (dist < BALL_RADIUS + 6) {
      // 碰撞响应
      const cnx = distX / dist;
      const cny = distY / dist;
      this._ball.x = closestX + cnx * (BALL_RADIUS + 7);
      this._ball.y = closestY + cny * (BALL_RADIUS + 7);

      const dot = this._ball.vx * cnx + this._ball.vy * cny;
      this._ball.vx -= 2 * dot * cnx;
      this._ball.vy -= 2 * dot * cny;

      // 挡板激活时给额外力
      if (flipper.active) {
        this._ball.vy -= 5;
        this._ball.vx += flipper.side === 'left' ? 2 : -2;
      }

      this._ball.vx *= BOUNCE_DAMPING;
      this._ball.vy *= BOUNCE_DAMPING;
    }
  }

  private renderFlipper(ctx: CanvasRenderingContext2D, flipper: FlipperState): void {
    const endX = flipper.x + Math.cos(flipper.angle) * FLIPPER_LENGTH;
    const endY = flipper.y + Math.sin(flipper.angle) * FLIPPER_LENGTH;

    ctx.strokeStyle = COLORS.FLIPPER;
    ctx.lineWidth = 12;
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.moveTo(flipper.x, flipper.y);
    ctx.lineTo(endX, endY);
    ctx.stroke();
  }

  // ========== Getters ==========

  get ball() { return this._ball; }
  get leftFlipper() { return this._leftFlipper; }
  get rightFlipper() { return this._rightFlipper; }
  get bumpers() { return this._bumpers; }
  get targets() { return this._targets; }
  get lives() { return this._lives; }
  get launcherCompressed() { return this._launcherCompressed; }
}

import { GameEngine } from '@/core/GameEngine';
import {
  BOARD_WIDTH, BOARD_HEIGHT, CELL_SIZE, BOARD_GAP,
  CANVAS_WIDTH, CANVAS_HEIGHT, TETROMINOS, TETROMINO_TYPES,
  ATTACK_LINES, GARBAGE_COLOR, BASE_SPEED, SPEED_DECREASE, MIN_SPEED,
  AI_THINK_TIME, COLORS,
} from './constants';

interface Piece {
  type: string;
  shape: number[][];
  color: string;
  x: number;
  y: number;
}

interface BoardState {
  grid: (string | null)[][];
  piece: Piece | null;
  nextPiece: Piece | null;
  score: number;
  level: number;
  lines: number;
  dropTimer: number;
  pendingGarbage: number;
  gameOver: boolean;
}

export class TetrisBattleEngine extends GameEngine {
  private _player1: BoardState = this.createEmptyBoard();
  private _player2: BoardState = this.createEmptyBoard();
  private _aiTimer = 0;
  private _winner: number | null = null;

  protected onInit(): void {
    this._player1 = this.createEmptyBoard();
    this._player2 = this.createEmptyBoard();
    this._winner = null;
  }

  protected onStart(): void {
    this._player1 = this.createEmptyBoard();
    this._player2 = this.createEmptyBoard();
    this._winner = null;
    this._aiTimer = 0;
    this.spawnPiece(this._player1);
    this.spawnPiece(this._player2);
  }

  protected update(deltaTime: number): void {
    if (this._status !== 'playing') return;

    // 玩家1自动下落
    this.updateBoard(this._player1, deltaTime);
    // AI 玩家2
    this.updateAI(deltaTime);
    this.updateBoard(this._player2, deltaTime);

    // 检查胜负
    if (this._player1.gameOver && !this._player2.gameOver) {
      this._winner = 2;
      this.gameOver();
    } else if (this._player2.gameOver && !this._player1.gameOver) {
      this._winner = 1;
      this.gameOver();
    } else if (this._player1.gameOver && this._player2.gameOver) {
      this._winner = 0;
      this.gameOver();
    }
  }

  protected onRender(ctx: CanvasRenderingContext2D, w: number, h: number): void {
    ctx.fillStyle = COLORS.BACKGROUND;
    ctx.fillRect(0, 0, w, h);

    const boardW = BOARD_WIDTH * CELL_SIZE;
    const boardH = BOARD_HEIGHT * CELL_SIZE;
    const totalW = boardW * 2 + BOARD_GAP;
    const offsetX = (w - totalW) / 2;
    const offsetY = (h - boardH) / 2;

    // 渲染玩家1棋盘
    this.renderBoard(ctx, this._player1, offsetX, offsetY, 'P1 (你)');
    // 渲染玩家2棋盘
    this.renderBoard(ctx, this._player2, offsetX + boardW + BOARD_GAP, offsetY, 'P2 (AI)');

    // 中间 VS
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 20px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('VS', w / 2, offsetY + boardH / 2);
  }

  handleKeyDown(key: string): void {
    if (this._status !== 'playing') return;
    const p = this._player1;
    if (!p.piece || p.gameOver) return;

    switch (key) {
      case 'a': case 'A': case 'ArrowLeft':
        this.movePiece(p, -1, 0);
        break;
      case 'd': case 'D': case 'ArrowRight':
        this.movePiece(p, 1, 0);
        break;
      case 's': case 'S': case 'ArrowDown':
        this.movePiece(p, 0, 1);
        this.addScore(1);
        break;
      case 'w': case 'W': case 'ArrowUp':
        this.rotatePiece(p);
        break;
      case ' ':
        this.hardDrop(p);
        break;
    }
  }

  handleKeyUp(_key: string): void {}

  getState(): Record<string, unknown> {
    return {
      player1: this._player1,
      player2: this._player2,
      winner: this._winner,
    };
  }

  // ========== 棋盘逻辑 ==========

  private createEmptyBoard(): BoardState {
    return {
      grid: Array.from({ length: BOARD_HEIGHT }, () => Array(BOARD_WIDTH).fill(null)),
      piece: null,
      nextPiece: null,
      score: 0,
      level: 1,
      lines: 0,
      dropTimer: 0,
      pendingGarbage: 0,
      gameOver: false,
    };
  }

  private createRandomPiece(): Piece {
    const type = TETROMINO_TYPES[Math.floor(Math.random() * TETROMINO_TYPES.length)];
    const tetro = TETROMINOS[type];
    return {
      type,
      shape: tetro.shape.map(r => [...r]),
      color: tetro.color,
      x: Math.floor((BOARD_WIDTH - tetro.shape[0].length) / 2),
      y: 0,
    };
  }

  private spawnPiece(board: BoardState): void {
    board.piece = board.nextPiece || this.createRandomPiece();
    board.nextPiece = this.createRandomPiece();
    board.piece.x = Math.floor((BOARD_WIDTH - board.piece.shape[0].length) / 2);
    board.piece.y = 0;

    if (this.checkCollision(board, board.piece, 0, 0)) {
      board.gameOver = true;
    }
  }

  private checkCollision(board: BoardState, piece: Piece, dx: number, dy: number): boolean {
    for (let r = 0; r < piece.shape.length; r++) {
      for (let c = 0; c < piece.shape[r].length; c++) {
        if (!piece.shape[r][c]) continue;
        const nx = piece.x + c + dx;
        const ny = piece.y + r + dy;
        if (nx < 0 || nx >= BOARD_WIDTH || ny >= BOARD_HEIGHT) return true;
        if (ny >= 0 && board.grid[ny][nx] !== null) return true;
      }
    }
    return false;
  }

  private movePiece(board: BoardState, dx: number, dy: number): boolean {
    if (!board.piece) return false;
    if (!this.checkCollision(board, board.piece, dx, dy)) {
      board.piece.x += dx;
      board.piece.y += dy;
      return true;
    }
    return false;
  }

  private rotatePiece(board: BoardState): void {
    if (!board.piece) return;
    const rotated = board.piece.shape[0].map((_, i) =>
      board.piece!.shape.map(row => row[i]).reverse()
    );
    const oldShape = board.piece.shape;
    board.piece.shape = rotated;
    if (this.checkCollision(board, board.piece, 0, 0)) {
      // 尝试墙踢
      if (!this.checkCollision(board, board.piece, -1, 0)) {
        board.piece.x -= 1;
      } else if (!this.checkCollision(board, board.piece, 1, 0)) {
        board.piece.x += 1;
      } else {
        board.piece.shape = oldShape;
      }
    }
  }

  private hardDrop(board: BoardState): void {
    if (!board.piece) return;
    let dropDist = 0;
    while (!this.checkCollision(board, board.piece, 0, 1)) {
      board.piece.y++;
      dropDist++;
    }
    this.addScore(dropDist * 2);
    this.lockPiece(board);
  }

  private lockPiece(board: BoardState): void {
    if (!board.piece) return;
    for (let r = 0; r < board.piece.shape.length; r++) {
      for (let c = 0; c < board.piece.shape[r].length; c++) {
        if (board.piece.shape[r][c]) {
          const gy = board.piece.y + r;
          const gx = board.piece.x + c;
          if (gy >= 0 && gy < BOARD_HEIGHT && gx >= 0 && gx < BOARD_WIDTH) {
            board.grid[gy][gx] = board.piece.color;
          }
        }
      }
    }

    // 消行
    const linesCleared = this.clearLines(board);
    if (linesCleared > 0) {
      board.lines += linesCleared;
      board.level = Math.floor(board.lines / 10) + 1;
      board.score += linesCleared * 100 * board.level;

      // 攻击对手
      const attackLines = ATTACK_LINES[linesCleared] || 0;
      if (attackLines > 0) {
        const opponent = board === this._player1 ? this._player2 : this._player1;
        opponent.pendingGarbage += attackLines;
      }
    }

    // 处理待接收垃圾行
    if (board.pendingGarbage > 0) {
      this.addGarbageLines(board, board.pendingGarbage);
      board.pendingGarbage = 0;
    }

    this.spawnPiece(board);
  }

  private clearLines(board: BoardState): number {
    let cleared = 0;
    for (let r = BOARD_HEIGHT - 1; r >= 0; r--) {
      if (board.grid[r].every(cell => cell !== null)) {
        board.grid.splice(r, 1);
        board.grid.unshift(Array(BOARD_WIDTH).fill(null));
        cleared++;
        r++; // 重新检查当前行
      }
    }
    return cleared;
  }

  private addGarbageLines(board: BoardState, count: number): void {
    const holePos = Math.floor(Math.random() * BOARD_WIDTH);
    for (let i = 0; i < count; i++) {
      board.grid.shift();
      const line: (string | null)[] = Array(BOARD_WIDTH).fill(GARBAGE_COLOR);
      line[holePos] = null;
      board.grid.push(line);
    }
    // 如果当前方块被推上去导致碰撞，游戏结束
    if (board.piece && this.checkCollision(board, board.piece, 0, 0)) {
      board.gameOver = true;
    }
  }

  private updateBoard(board: BoardState, deltaTime: number): void {
    if (board.gameOver || !board.piece) return;

    const speed = Math.max(MIN_SPEED, BASE_SPEED - (board.level - 1) * SPEED_DECREASE);
    board.dropTimer += deltaTime;
    if (board.dropTimer >= speed) {
      board.dropTimer = 0;
      if (!this.movePiece(board, 0, 1)) {
        this.lockPiece(board);
      }
    }
  }

  // ========== AI ==========

  private updateAI(deltaTime: number): void {
    if (this._player2.gameOver || !this._player2.piece) return;

    this._aiTimer += deltaTime;
    if (this._aiTimer < AI_THINK_TIME) return;
    this._aiTimer = 0;

    this.aiMove(this._player2);
  }

  private aiMove(board: BoardState): void {
    if (!board.piece) return;

    let bestScore = -Infinity;
    let bestRotation = 0;
    let bestX = 0;

    for (let rot = 0; rot < 4; rot++) {
      let testPiece: Piece = {
        ...board.piece,
        shape: board.piece.shape.map(r => [...r]),
      };
      for (let r = 0; r < rot; r++) {
        testPiece.shape = testPiece.shape[0].map((_, i) =>
          testPiece.shape.map(row => row[i]).reverse()
        );
      }

      const pieceWidth = testPiece.shape[0].length;
      for (let x = -2; x < BOARD_WIDTH; x++) {
        testPiece.x = x;
        testPiece.y = 0;

        if (this.checkCollisionForTest(board.grid, testPiece, 0, 0)) continue;

        // 找落点
        let dropY = 0;
        while (!this.checkCollisionForTest(board.grid, testPiece, 0, dropY + 1)) {
          dropY++;
        }
        testPiece.y = dropY;

        // 评估
        const score = this.evaluatePosition(board.grid, testPiece);
        if (score > bestScore) {
          bestScore = score;
          bestRotation = rot;
          bestX = x;
        }
      }
    }

    // 执行最佳移动
    for (let r = 0; r < bestRotation; r++) {
      this.rotatePiece(board);
    }
    if (board.piece) {
      const dx = bestX - board.piece.x;
      if (dx < 0) {
        for (let i = 0; i < -dx; i++) this.movePiece(board, -1, 0);
      } else {
        for (let i = 0; i < dx; i++) this.movePiece(board, 1, 0);
      }
      this.hardDrop(board);
    }
  }

  private checkCollisionForTest(grid: (string | null)[][], piece: Piece, dx: number, dy: number): boolean {
    for (let r = 0; r < piece.shape.length; r++) {
      for (let c = 0; c < piece.shape[r].length; c++) {
        if (!piece.shape[r][c]) continue;
        const nx = piece.x + c + dx;
        const ny = piece.y + r + dy;
        if (nx < 0 || nx >= BOARD_WIDTH || ny >= BOARD_HEIGHT) return true;
        if (ny >= 0 && grid[ny][nx] !== null) return true;
      }
    }
    return false;
  }

  private evaluatePosition(grid: (string | null)[][], piece: Piece): number {
    // 模拟放置
    const testGrid = grid.map(r => [...r]);
    for (let r = 0; r < piece.shape.length; r++) {
      for (let c = 0; c < piece.shape[r].length; c++) {
        if (piece.shape[r][c]) {
          const gy = piece.y + r;
          const gx = piece.x + c;
          if (gy >= 0 && gy < BOARD_HEIGHT && gx >= 0 && gx < BOARD_WIDTH) {
            testGrid[gy][gx] = piece.color;
          }
        }
      }
    }

    let score = 0;

    // 消行加分
    for (let r = 0; r < BOARD_HEIGHT; r++) {
      if (testGrid[r].every(c => c !== null)) score += 100;
    }

    // 高度惩罚
    for (let r = 0; r < BOARD_HEIGHT; r++) {
      for (let c = 0; c < BOARD_WIDTH; c++) {
        if (testGrid[r][c] !== null) {
          score -= (BOARD_HEIGHT - r) * 0.5;
        }
      }
    }

    // 空洞惩罚
    for (let c = 0; c < BOARD_WIDTH; c++) {
      let foundBlock = false;
      for (let r = 0; r < BOARD_HEIGHT; r++) {
        if (testGrid[r][c] !== null) foundBlock = true;
        else if (foundBlock) score -= 5;
      }
    }

    return score;
  }

  // ========== 渲染 ==========

  private renderBoard(ctx: CanvasRenderingContext2D, board: BoardState, x: number, y: number, label: string): void {
    const boardW = BOARD_WIDTH * CELL_SIZE;
    const boardH = BOARD_HEIGHT * CELL_SIZE;

    // 背景
    ctx.fillStyle = COLORS.BOARD_BG;
    ctx.fillRect(x, y, boardW, boardH);

    // 网格线
    ctx.strokeStyle = COLORS.GRID_LINE;
    ctx.lineWidth = 0.5;
    for (let r = 0; r <= BOARD_HEIGHT; r++) {
      ctx.beginPath();
      ctx.moveTo(x, y + r * CELL_SIZE);
      ctx.lineTo(x + boardW, y + r * CELL_SIZE);
      ctx.stroke();
    }
    for (let c = 0; c <= BOARD_WIDTH; c++) {
      ctx.beginPath();
      ctx.moveTo(x + c * CELL_SIZE, y);
      ctx.lineTo(x + c * CELL_SIZE, y + boardH);
      ctx.stroke();
    }

    // 已放置方块
    for (let r = 0; r < BOARD_HEIGHT; r++) {
      for (let c = 0; c < BOARD_WIDTH; c++) {
        if (board.grid[r][c]) {
          ctx.fillStyle = board.grid[r][c]!;
          ctx.fillRect(x + c * CELL_SIZE + 1, y + r * CELL_SIZE + 1, CELL_SIZE - 2, CELL_SIZE - 2);
        }
      }
    }

    // 当前方块
    if (board.piece) {
      ctx.fillStyle = board.piece.color;
      for (let r = 0; r < board.piece.shape.length; r++) {
        for (let c = 0; c < board.piece.shape[r].length; c++) {
          if (board.piece.shape[r][c]) {
            ctx.fillRect(
              x + (board.piece.x + c) * CELL_SIZE + 1,
              y + (board.piece.y + r) * CELL_SIZE + 1,
              CELL_SIZE - 2,
              CELL_SIZE - 2
            );
          }
        }
      }
    }

    // 边框
    ctx.strokeStyle = COLORS.BORDER;
    ctx.lineWidth = 2;
    ctx.strokeRect(x, y, boardW, boardH);

    // 标签
    ctx.fillStyle = COLORS.LABEL_TEXT;
    ctx.font = '14px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(label, x + boardW / 2, y - 8);

    // 分数
    ctx.fillStyle = COLORS.SCORE_TEXT;
    ctx.font = '12px sans-serif';
    ctx.fillText(`Score: ${board.score} Lines: ${board.lines}`, x + boardW / 2, y + boardH + 16);
  }

  // ========== Getters ==========

  get player1() { return this._player1; }
  get player2() { return this._player2; }
  get winner() { return this._winner; }
}

