import { GameEngine } from '@/core/GameEngine';
import {
  GRID_ROWS, GRID_COLS, CELL_SIZE,
  CANVAS_WIDTH, CANVAS_HEIGHT, PATTERN_COUNT,
  PATTERN_EMOJIS, COLORS, GAME_TIME, MAX_PATH_TURNS,
} from './constants';

interface Point { row: number; col: number; }

export class MahjongConnectEngine extends GameEngine {
  private _grid: number[][] = [];
  private _selected: Point | null = null;
  private _hintPair: [Point, Point] | null = null;
  private _remainingPairs = 0;
  private _timer = 0;
  private _combo = 0;
  private _path: Point[] = [];

  protected onInit(): void {
    this.generateBoard();
  }

  protected onStart(): void {
    this._timer = 0;
    this._combo = 0;
  }

  protected update(deltaTime: number): void {
    if (this._status === 'playing') {
      this._timer += deltaTime / 1000;
      if (this._timer >= GAME_TIME) {
        this.gameOver();
      }
    }
  }

  protected onRender(ctx: CanvasRenderingContext2D, w: number, h: number): void {
    ctx.fillStyle = COLORS.BACKGROUND;
    ctx.fillRect(0, 0, w, h);

    const offsetX = (w - GRID_COLS * CELL_SIZE) / 2;
    const offsetY = (h - GRID_ROWS * CELL_SIZE) / 2;

    for (let r = 0; r < GRID_ROWS; r++) {
      for (let c = 0; c < GRID_COLS; c++) {
        const x = offsetX + c * CELL_SIZE;
        const y = offsetY + r * CELL_SIZE;

        if (this._grid[r][c] === 0) continue;

        ctx.fillStyle = COLORS.CELL_BG;
        ctx.fillRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);

        if (this._selected && this._selected.row === r && this._selected.col === c) {
          ctx.strokeStyle = COLORS.CELL_SELECTED;
          ctx.lineWidth = 3;
          ctx.strokeRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);
        }

        if (this._hintPair) {
          const isHint = (this._hintPair[0].row === r && this._hintPair[0].col === c) ||
            (this._hintPair[1].row === r && this._hintPair[1].col === c);
          if (isHint) {
            ctx.strokeStyle = COLORS.CELL_HINT;
            ctx.lineWidth = 2;
            ctx.strokeRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);
          }
        }

        const patternIndex = this._grid[r][c] - 1;
        if (patternIndex >= 0 && patternIndex < PATTERN_EMOJIS.length) {
          ctx.font = '28px sans-serif';
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillStyle = COLORS.TEXT_COLOR;
          ctx.fillText(PATTERN_EMOJIS[patternIndex], x + CELL_SIZE / 2, y + CELL_SIZE / 2);
        }
      }
    }
  }

  handleKeyDown(key: string): void {
    if (key === 'h' || key === 'H') this.showHint();
    if (key === 's' || key === 'S') this.shuffle();
  }

  handleKeyUp(_key: string): void {}

  getState(): Record<string, unknown> {
    return {
      grid: this._grid,
      selected: this._selected,
      remainingPairs: this._remainingPairs,
      timer: this._timer,
      combo: this._combo,
    };
  }

  selectCell(row: number, col: number): void {
    if (this._status !== 'playing') return;
    if (row < 0 || row >= GRID_ROWS || col < 0 || col >= GRID_COLS) return;
    if (this._grid[row][col] === 0) return;

    if (!this._selected) {
      this._selected = { row, col };
      this._hintPair = null;
      return;
    }

    if (this._selected.row === row && this._selected.col === col) {
      this._selected = null;
      return;
    }

    const path = this.findPath(this._selected, { row, col });
    if (path && this._grid[this._selected.row][this._selected.col] === this._grid[row][col]) {
      this._path = path;
      this._grid[this._selected.row][this._selected.col] = 0;
      this._grid[row][col] = 0;
      this._remainingPairs--;
      this._combo++;
      this.addScore(100 * this._combo);
      this._selected = null;
      this._hintPair = null;

      if (this._remainingPairs <= 0) {
        this.addScore(Math.max(0, Math.floor((GAME_TIME - this._timer) * 10)));
        this.gameOver();
        return;
      }

      if (!this.hasValidPairs()) {
        this.shuffle();
      }
    } else {
      this._selected = { row, col };
      this._combo = 0;
    }
  }

  showHint(): void {
    const pair = this.findValidPair();
    if (pair) this._hintPair = pair;
  }

  shuffle(): void {
    const remaining: number[] = [];
    const positions: Point[] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      for (let c = 0; c < GRID_COLS; c++) {
        if (this._grid[r][c] !== 0) {
          remaining.push(this._grid[r][c]);
          positions.push({ row: r, col: c });
        }
      }
    }
    for (let i = remaining.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [remaining[i], remaining[j]] = [remaining[j], remaining[i]];
    }
    for (let i = 0; i < positions.length; i++) {
      this._grid[positions[i].row][positions[i].col] = remaining[i];
    }
    this._selected = null;
    this._hintPair = null;
  }

  private findPath(from: Point, to: Point): Point[] | null {
    const dirs = [[-1, 0], [1, 0], [0, -1], [0, 1]];
    const visited = new Map<string, number>();
    const queue: { row: number; col: number; dir: number; turns: number; path: Point[] }[] = [];

    for (let d = 0; d < 4; d++) {
      const nr = from.row + dirs[d][0];
      const nc = from.col + dirs[d][1];
      if (nr === to.row && nc === to.col) return [from, to];
      if (this.isWalkable(nr, nc)) {
        const key = `${nr},${nc},${d}`;
        visited.set(key, 0);
        queue.push({ row: nr, col: nc, dir: d, turns: 0, path: [from, { row: nr, col: nc }] });
      }
    }

    let head = 0;
    while (head < queue.length) {
      const curr = queue[head++];
      for (let d = 0; d < 4; d++) {
        const newTurns = curr.dir === d ? curr.turns : curr.turns + 1;
        if (newTurns > MAX_PATH_TURNS) continue;
        const nr = curr.row + dirs[d][0];
        const nc = curr.col + dirs[d][1];
        if (nr === to.row && nc === to.col) return [...curr.path, to];
        if (!this.isWalkable(nr, nc)) continue;
        const key = `${nr},${nc},${d}`;
        if (visited.has(key) && (visited.get(key) ?? Infinity) <= newTurns) continue;
        visited.set(key, newTurns);
        queue.push({ row: nr, col: nc, dir: d, turns: newTurns, path: [...curr.path, { row: nr, col: nc }] });
      }
    }
    return null;
  }

  private isWalkable(row: number, col: number): boolean {
    if (row < -1 || row > GRID_ROWS || col < -1 || col > GRID_COLS) return false;
    if (row < 0 || row >= GRID_ROWS || col < 0 || col >= GRID_COLS) return true;
    return this._grid[row][col] === 0;
  }

  private findValidPair(): [Point, Point] | null {
    const cells: { point: Point; pattern: number }[] = [];
    for (let r = 0; r < GRID_ROWS; r++) {
      for (let c = 0; c < GRID_COLS; c++) {
        if (this._grid[r][c] !== 0) cells.push({ point: { row: r, col: c }, pattern: this._grid[r][c] });
      }
    }
    for (let i = 0; i < cells.length; i++) {
      for (let j = i + 1; j < cells.length; j++) {
        if (cells[i].pattern === cells[j].pattern) {
          if (this.findPath(cells[i].point, cells[j].point)) return [cells[i].point, cells[j].point];
        }
      }
    }
    return null;
  }

  private hasValidPairs(): boolean { return this.findValidPair() !== null; }

  private generateBoard(): void {
    const totalCells = GRID_ROWS * GRID_COLS;
    const patterns: number[] = [];
    for (let i = 0; i < PATTERN_COUNT; i++) {
      const count = totalCells / PATTERN_COUNT;
      for (let j = 0; j < count; j++) patterns.push(i + 1);
    }
    for (let i = patterns.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [patterns[i], patterns[j]] = [patterns[j], patterns[i]];
    }
    this._grid = [];
    let idx = 0;
    for (let r = 0; r < GRID_ROWS; r++) {
      this._grid[r] = [];
      for (let c = 0; c < GRID_COLS; c++) {
        this._grid[r][c] = patterns[idx++];
      }
    }
    this._remainingPairs = totalCells / 2;
    this._selected = null;
    this._hintPair = null;
    this._path = [];
  }

  get grid() { return this._grid; }
  get selected() { return this._selected; }
  get remainingPairs() { return this._remainingPairs; }
  get timer() { return this._timer; }
  get combo() { return this._combo; }
  get hintPair() { return this._hintPair; }
}

