      engine.handleKeyDown(' ');
      // 硬降后方块应该被锁定
      expect(engine.player1.piece).not.toBe(engine.player1.piece); // 新方块
    });
  });

  describe('消行', () => {
    it('填满一行可以消除', () => {
      engine.start();
      // 手动填满一行
      for (let c = 0; c < BOARD_WIDTH; c++) {
        engine.player1.grid[BOARD_HEIGHT - 1][c] = '#ff0000';
      }
      const lines = (engine as any).clearLines(engine.player1);
      expect(lines).toBe(1);
    });

    it('消多行', () => {
      engine.start();
      for (let r = BOARD_HEIGHT - 2; r < BOARD_HEIGHT; r++) {
        for (let c = 0; c < BOARD_WIDTH; c++) {
          engine.player1.grid[r][c] = '#ff0000';
        }
      }
      const lines = (engine as any).clearLines(engine.player1);
      expect(lines).toBe(2);
    });
  });

  describe('攻击机制', () => {
    it('ATTACK_LINES 规则正确', () => {
      expect(ATTACK_LINES[1]).toBe(0);
      expect(ATTACK_LINES[2]).toBe(1);
      expect(ATTACK_LINES[3]).toBe(2);
      expect(ATTACK_LINES[4]).toBe(4);
    });

    it('消行后对手接收垃圾行', () => {
      engine.start();
      // 填满 4 行触发攻击
      for (let r = BOARD_HEIGHT - 4; r < BOARD_HEIGHT; r++) {
        for (let c = 0; c < BOARD_WIDTH; c++) {
          engine.player1.grid[r][c] = '#ff0000';
        }
      }
      // 模拟锁定方块
      const piece = engine.player1.piece;
      if (piece) {
        piece.y = BOARD_HEIGHT - 5;
        (engine as any).lockPiece(engine.player1);
      }
      expect(engine.player2.pendingGarbage).toBeGreaterThan(0);
    });

    it('垃圾行添加到棋盘底部', () => {
      engine.start();
      (engine as any).addGarbageLines(engine.player2, 2);
      // 底部两行应该是垃圾行
      let garbageCount = 0;
      for (let c = 0; c < BOARD_WIDTH; c++) {
        if (engine.player2.grid[BOARD_HEIGHT - 1][c] !== null) garbageCount++;
        if (engine.player2.grid[BOARD_HEIGHT - 2][c] !== null) garbageCount++;
      }
      expect(garbageCount).toBeGreaterThan(0);
    });
  });

  describe('AI', () => {
    it('AI 自动操作', () => {
      engine.start();
      // 模拟一段时间让 AI 运行
      (engine as any)._aiTimer = 1000;
      (engine as any).updateAI(100);
      // AI 应该已经移动了
      expect(true).toBe(true);
    });
  });

  describe('胜负判定', () => {
    it('玩家1 game over 则玩家2 胜', () => {
      engine.start();
      engine.player1.gameOver = true;
      (engine as any).update(16);
      expect(engine.winner).toBe(2);
    });

    it('玩家2 game over 则玩家1 胜', () => {
      engine.start();
      engine.player2.gameOver = true;
      (engine as any).update(16);
      expect(engine.winner).toBe(1);
    });
  });

  describe('getState', () => {
    it('返回完整状态', () => {
      const state = engine.getState();
      expect(state).toHaveProperty('player1');
      expect(state).toHaveProperty('player2');
      expect(state).toHaveProperty('winner');
    });
  });

  describe('生命周期', () => {
    it('reset 后状态为 idle', () => {
      engine.start();
      engine.reset();
      expect(engine.status).toBe('idle');
    });

    it('destroy 后清理', () => {
      engine.destroy();
      expect(engine.status).toBe('idle');
    });
  });
});

